SELECT COUNT(DISTINCT order_id) AS order_count
FROM olist_orders
WHERE strftime(order_purchase_timestamp, '%Y-%m') = '2017-11';

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE strftime(order_purchase_timestamp, '%Y-%m') = '2017-11';

SELECT 100.0 * COUNT(CASE WHEN order_status != 'delivered' THEN 1 END) / COUNT(order_status) AS proportion_not_delivered
FROM olist_orders
WHERE order_status IS NOT NULL;

SELECT
    (SELECT SUM(freight) FROM northwind_orders) /
    (SELECT SUM(unitPrice * quantity * (1 - discount)) FROM northwind_order_details) * 100 AS freight_pct_of_revenue; SELECT SUM(unitPrice * quantity * (1 - discount)) AS total_trading_revenue FROM northwind_order_details;; SELECT SUM(freight) AS total_freight_cost FROM northwind_orders;

SELECT AVG(review_score) AS overall_avg_review_score
FROM olist_order_reviews
WHERE review_score IS NOT NULL;; SELECT 100.0 * SUM(CASE WHEN review_score = 1 THEN 1 ELSE 0 END) / COUNT(*) AS pct_score_1 FROM olist_order_reviews WHERE review_score IS NOT NULL;; SELECT strftime(review_creation_date, '%Y-%m') AS review_month, AVG(review_score) AS avg_review_score FROM olist_order_reviews WHERE review_creation_date IS NOT NULL AND review_score IS NOT NULL GROUP BY review_month ORDER BY review_month; SELECT o.order_status, AVG(r.review_score) AS avg_review_score FROM olist_order_reviews r JOIN olist_orders o ON r.order_id = o.order_id WHERE r.review_score IS NOT NULL GROUP BY o.order_status ORDER BY avg_review_score ASC;; SELECT p.product_category_name, AVG(r.review_score) AS avg_review_score FROM olist_order_reviews r JOIN olist_orders o ON r.order_id = o.order_id JOIN olist_order_items oi ON o.order_id = oi.order_id JOIN olist_products p ON oi.product_id = p.product_id WHERE r.review_score IS NOT NULL AND p.product_category_name IS NOT NULL GROUP BY p.product_category_name ORDER BY avg_review_score ASC LIMIT 10;

